import openai
from flask import Flask, request, render_template

app = Flask(__name__)

# Set up OpenAI API key
openai.api_key = "your_openai_api_key_here"

@app.route('/', methods=['GET', 'POST'])
def index():
    if request.method == 'POST':
        paper_text = request.form['paper_text']
        summary = generate_summary(paper_text)
        questions = ask_questions(summary)
        return render_template('index.html', summary=summary, questions=questions)
    return render_template('index.html')

def generate_summary(paper_text):
    response = openai.Completion.create(
        engine="text-davinci-002",
        prompt=f"Summarize the following text:\n\n{paper_text}",
        max_tokens=500,
        n=1,
        stop=None,
        temperature=0.5,
    )
    return response.choices[0].text.strip()

def ask_questions(summary):
    response = openai.Completion.create(
        engine="text-davinci-002",
        prompt=f"Generate 3 questions based on the following summary:\n\n{summary}",
        max_tokens=150,
        n=3,
        stop=None,
        temperature=0.5,
    )
    return [choice.text.strip() for choice in response.choices]

if __name__ == '__main__':
    app.run(debug=True)
